import openpyxl
wb = openpyxl.load_workbook('input.xlsx', data_only=True)
print('Sheet names:', wb.sheetnames)
for s in wb.sheetnames:
    ws = wb[s]
    print(f'\n=== {s} === (rows={ws.max_row}, cols={ws.max_column})')
    for r in range(1, min(ws.max_row+1, 30)):
        row_data = []
        for c in range(1, min(ws.max_column+1, 25)):
            v = ws.cell(r, c).value
            if v is not None:
                row_data.append(f'{openpyxl.utils.get_column_letter(c)}{r}={v}')
        if row_data:
            print(f'  Row {r}: {row_data}')
"

